tles.push(title); // \u5c06\u6807\u9898\u5b58\u5165\u6570\u7ec4\r\n      links.push(link);   // \u5c06\u94fe\u63a5\u5b58\u5165\u6570\u7ec4\r\n    }\r\n    rowIndex++; // \u884c\u7d22\u5f15\u9012\u589e\uff0c\u5904\u7406\u4e0b\u4e00\u884c\r\n  }\r\n  let rangeB = Api.GetSelection();\r\n  rangeB.ForEach(function (cell) {\r\n    let cellValue = cell.GetValue();\r\n    // \u68c0\u67e5\u5355\u5143\u683c\u503c\u662f\u5426\u4e0e\u6807\u9898\u6570\u7ec4\u4e2d\u7684\u67d0\u9879\u5339\u914d\r\n    let index = titles.indexOf(cellValue);\r\n    if (index !== -1) {\r\n      let title = titles[index];\r\n      let link = links[index];\r\n      let address = cell.GetAddress(true, true, "xlA1", false);\r\n      // \u5728 worksheetB \u4e2d\u8bbe\u7f6e\u8d85\u94fe\u63a5\r\n      worksheetB.SetHyperlink(address, link, "", title);\r\n    }\r\n  });\r\n})();\n'})}),"\n",(0,s.jsxs)(r.p,{children:["\u4f7f\u7528\u65b9\u6cd5: ",(0,s.jsx)(r.a,{href:"/api.onlyoffice.com-preview/zh-CN/docs/office-api/usage-api/spreadsheet-api/Api/Methods/GetSheet",children:"GetSheet"}),", ",(0,s.jsx)(r.a,{href:"/api.onlyoffice.com-preview/zh-CN/docs/office-api/usage-api/spreadsheet-api/ApiWorksheet/Methods/GetRangeByNumber",children:"GetRangeByNumber"}),", ",(0,s.jsx)(r.a,{href:"/api.onlyoffice.com-preview/zh-CN/docs/office-api/usage-api/spreadsheet-api/ApiRange/Methods/GetValue",children:"GetValue"}),", ",(0,s.jsx)(r.a,{href:"/api.onlyoffice.com-preview/zh-CN/docs/office-api/usage-api/spreadsheet-api/Api/Methods/GetSelection",children:"GetSelection"}),", ",(0,s.jsx)(r.a,{href:"/api.onlyoffice.com-preview/zh-CN/docs/office-api/usage-api/spreadsheet-api/ApiRange/Methods/ForEach",children:"ForEach"}),", ",(0,s.jsx)(r.a,{href:"/api.onlyoffice.com-preview/zh-CN/docs/office-api/usage-api/spreadsheet-api/ApiRange/Methods/GetAddress",children:"GetAddress"}),", ",(0,s.jsx)(r.a,{href:"/api.onlyoffice.com-preview/zh-CN/docs/office-api/usage-api/spreadsheet-api/ApiWorksheet/Methods/SetHyperlink",children:"SetHyperlink"})]